// History — 100 questions
export const historyQuestions = [
  {id:'his-001',subject_id:'history',subject_name:'History',topic:'World Civilisations',difficulty:'foundation',type:'multiple_choice',question:'The Kingdom of Benin was located in which continent?',options:['Asia','Europe','Africa','South America'],correct_index:2,explanation:'The Kingdom of Benin was located in West Africa, in what is now southern Nigeria. It was powerful from the 13th to the 19th century.'},
  {id:'his-002',subject_id:'history',subject_name:'History',topic:'World Civilisations',difficulty:'foundation',type:'multiple_choice',question:'What was the Kingdom of Benin most famous for producing?',options:['Silk and spices','Bronze sculptures and artworks','Gold coins','Cotton textiles'],correct_index:1,explanation:'Benin\'s royal court was renowned for its extraordinary bronze plaques and sculptures, which depicted rulers, ceremonies and court life.'},
  {id:'his-003',subject_id:'history',subject_name:'History',topic:'World Civilisations',difficulty:'foundation',type:'multiple_choice',question:'Who was the ruler of the Mali Empire who made a famous pilgrimage to Mecca around 1324?',options:['Sundiata Keita','Shaka Zulu','Mansa Musa','Ibn Battuta'],correct_index:2,explanation:'Mansa Musa was the ruler of the Mali Empire c.1312–1337. His pilgrimage to Mecca displayed such wealth that it allegedly caused inflation across North Africa and the Middle East.'},
  {id:'his-004',subject_id:'history',subject_name:'History',topic:'World Civilisations',difficulty:'foundation',type:'multiple_choice',question:'What period is called the "Islamic Golden Age" in Baghdad?',options:['1st–3rd centuries','8th–13th centuries','15th–16th centuries','18th–19th centuries'],correct_index:1,explanation:'The Islamic Golden Age (roughly 8th–13th centuries) was a period when scholars in Baghdad made extraordinary advances in mathematics, astronomy, medicine and philosophy.'},
  {id:'his-005',subject_id:'history',subject_name:'History',topic:'World Civilisations',difficulty:'core',type:'multiple_choice',question:'What invention from the Islamic Golden Age greatly influenced later European mathematics?',options:['The printing press','Arabic numerals and algebra','The compass','Steam power'],correct_index:1,explanation:'Al-Khwarizmi\'s work in Baghdad gave us algebra (the word comes from Arabic "al-jabr") and helped popularise the Hindu-Arabic numeral system used worldwide today.'},
  {id:'his-006',subject_id:'history',subject_name:'History',topic:'World Civilisations',difficulty:'core',type:'multiple_choice',question:'Why is the city of Timbuktu historically significant in relation to the Mali Empire?',options:['It was the site of the first battle of Mansa Musa','It was a major centre of Islamic learning and trade','It was where gold was mined','It was the birthplace of the Empire'],correct_index:1,explanation:'Timbuktu was a major centre of Islamic scholarship (home to the Sankore university) and an important hub for trans-Saharan trade in salt and gold.'},
  {id:'his-007',subject_id:'history',subject_name:'History',topic:'World Civilisations',difficulty:'core',type:'short_answer',question:'Explain why the Kingdom of Benin was considered a sophisticated civilisation. Give TWO pieces of evidence.',placeholder:'Name two specific features — e.g. complex art, organised army, long-distance trade, political system — and explain each...'},
  {id:'his-008',subject_id:'history',subject_name:'History',topic:'World Civilisations',difficulty:'stretch',type:'multiple_choice',question:'How did European contact in the 15th–19th centuries affect African civilisations like Benin?',options:['It had no effect','It generally strengthened them','It led to colonisation, exploitation and the destruction of many political structures','It immediately made them more prosperous'],correct_index:2,explanation:'European contact brought trade but also the slave trade, and eventually colonial conquest. Benin City was sacked by the British in 1897, and its bronze artworks were taken.'},
  {id:'his-009',subject_id:'history',subject_name:'History',topic:'World Civilisations',difficulty:'stretch',type:'short_answer',question:'Explain the concept of "Eurocentrism" in historical study and how studying civilisations like Benin and Mali challenges it.',placeholder:'Define Eurocentrism, then explain how Benin and Mali demonstrate sophisticated non-European societies that developed independently...'},
  {id:'his-010',subject_id:'history',subject_name:'History',topic:'The Tudors',difficulty:'foundation',type:'multiple_choice',question:'Which battle ended the Wars of the Roses and brought the Tudors to power?',options:['Battle of Agincourt','Battle of Hastings','Battle of Bosworth Field','Battle of Flodden'],correct_index:2,explanation:'The Battle of Bosworth Field in 1485 ended the Wars of the Roses. Henry Tudor defeated Richard III and became Henry VII, founding the Tudor dynasty.'},
  {id:'his-011',subject_id:'history',subject_name:'History',topic:'The Tudors',difficulty:'foundation',type:'multiple_choice',question:'How many wives did Henry VIII have?',options:['Two','Four','Six','Eight'],correct_index:2,explanation:'Henry VIII had six wives: Catherine of Aragon, Anne Boleyn, Jane Seymour, Anne of Cleves, Catherine Howard and Catherine Parr.'},
  {id:'his-012',subject_id:'history',subject_name:'History',topic:'The Tudors',difficulty:'foundation',type:'multiple_choice',question:'What was the Spanish Armada?',options:['A Spanish treasure fleet','A Spanish naval fleet sent to invade England in 1588','The personal guard of Philip II','A trading company'],correct_index:1,explanation:'The Spanish Armada was a fleet of 130 ships sent by King Philip II of Spain to invade England in 1588. It was defeated by English ships and severe storms.'},
  {id:'his-013',subject_id:'history',subject_name:'History',topic:'The Tudors',difficulty:'foundation',type:'multiple_choice',question:'What religion did Henry VIII create when he broke from Rome?',options:['Catholicism','Puritanism','The Church of England (Anglicanism)','Islam'],correct_index:2,explanation:'Henry VIII\'s Break with Rome in the 1530s led to the creation of the Church of England, with Henry as its Supreme Head — primarily to allow him to divorce Catherine of Aragon.'},
  {id:'his-014',subject_id:'history',subject_name:'History',topic:'The Tudors',difficulty:'core',type:'multiple_choice',question:'Why did Henry VIII want to annul his marriage to Catherine of Aragon?',options:['She was not rich enough','She was Catholic','She had not produced a male heir','She was too old to marry'],correct_index:2,explanation:'Henry needed a male heir to secure the Tudor dynasty. Catherine had only produced one surviving child, Mary. He sought an annulment to marry Anne Boleyn, who he hoped would give him a son.'},
  {id:'his-015',subject_id:'history',subject_name:'History',topic:'The Tudors',difficulty:'core',type:'multiple_choice',question:'What does the mnemonic "Divorced, Beheaded, Died, Divorced, Beheaded, Survived" describe?',options:['The fates of Henry\'s children','The fates of Henry\'s six wives in order','The Tudor monarchs in order','The events of the Reformation'],correct_index:1,explanation:'This mnemonic helps remember the fate of each of Henry VIII\'s six wives: Catherine of Aragon (divorced), Anne Boleyn (beheaded), Jane Seymour (died), Anne of Cleves (divorced), Catherine Howard (beheaded), Catherine Parr (survived).'},
  {id:'his-016',subject_id:'history',subject_name:'History',topic:'The Tudors',difficulty:'core',type:'short_answer',question:'Explain why historians consider the reign of Elizabeth I (1558–1603) a "Golden Age". Give TWO reasons.',placeholder:'Discuss two of: defeat of the Armada, cultural flourishing (Shakespeare), stability after religious turmoil, exploration and trade...'},
  {id:'his-017',subject_id:'history',subject_name:'History',topic:'The Tudors',difficulty:'stretch',type:'multiple_choice',question:'Why was the succession of Mary I significant for religious change in England?',options:['She made England permanently Protestant','She attempted to return England to Catholicism, burning around 300 Protestants — earning the nickname "Bloody Mary"','She had no religious policies','She brought the Reformation to completion'],correct_index:1,explanation:'Mary I was Catholic and tried to reverse the Protestant Reformation. She had approximately 300 Protestants burned at the stake, earning her the nickname "Bloody Mary".'},
  {id:'his-018',subject_id:'history',subject_name:'History',topic:'The Tudors',difficulty:'stretch',type:'short_answer',question:'To what extent was Henry VIII\'s Break with Rome driven by personal or religious reasons? Argue one side clearly.',placeholder:'You can argue it was primarily personal (wanting a divorce/male heir) or religious (genuine reforming beliefs) — use evidence to support ONE side...'},
  {id:'his-019',subject_id:'history',subject_name:'History',topic:'Historical skills',difficulty:'foundation',type:'multiple_choice',question:'What is a "primary source"?',options:['The most important source about a topic','A source created at the time of the event being studied','A source written by a professional historian','A source that is always reliable'],correct_index:1,explanation:'A primary source is created at the time of the event — e.g. a diary, a letter, a painting, or an object from the period. It gives direct evidence about the past.'},
  {id:'his-020',subject_id:'history',subject_name:'History',topic:'Historical skills',difficulty:'foundation',type:'multiple_choice',question:'What does "causation" mean in history?',options:['The effects of an event','Why something happened — the causes','The sequence of events in order','The most important event'],correct_index:1,explanation:'Causation asks "why did this happen?" Historians identify short-term (trigger) causes and long-term (underlying) causes.'},
  {id:'his-021',subject_id:'history',subject_name:'History',topic:'Historical skills',difficulty:'foundation',type:'multiple_choice',question:'What does "chronological" mean?',options:['In alphabetical order','In order of importance','In time order from earliest to latest','In geographical order'],correct_index:2,explanation:'Chronological means arranged in time order from the earliest to the most recent event.'},
  {id:'his-022',subject_id:'history',subject_name:'History',topic:'Historical skills',difficulty:'core',type:'multiple_choice',question:'What questions should you ask to evaluate a source?',options:['Who wrote it, when, why and how reliable is it?','Is it a book or a painting?','Is it long or short?','Is it in English?'],correct_index:0,explanation:'When evaluating a source consider: who created it? When? For what purpose? What might they have wanted to show or hide? This helps assess its reliability and usefulness.'},
  {id:'his-023',subject_id:'history',subject_name:'History',topic:'Historical skills',difficulty:'core',type:'multiple_choice',question:'What is "significance" in history?',options:['How long ago something happened','Why an event or person matters and what lasting impact they had','Whether something is true or false','The number of people involved in an event'],correct_index:1,explanation:'Significance asks: why does this event/person matter? Historians consider: how many people were affected, how long the impact lasted, how much it changed things.'},
  {id:'his-024',subject_id:'history',subject_name:'History',topic:'Historical skills',difficulty:'core',type:'short_answer',question:'Explain the difference between a cause and a consequence. Give one cause and one consequence of the English Reformation.',placeholder:'Define cause (reason why something happened) and consequence (result). Give one of each for the Reformation...'},
  {id:'his-025',subject_id:'history',subject_name:'History',topic:'Historical skills',difficulty:'stretch',type:'short_answer',question:'How reliable is a portrait of Henry VIII painted by a court artist as a source for understanding what Henry VIII was really like? Explain your reasoning.',placeholder:'Consider: court artist would want to flatter the king, so the portrait may not be realistic. Discuss purpose, audience and bias...'},
  {id:'his-026',subject_id:'history',subject_name:'History',topic:'The Tudors',difficulty:'foundation',type:'multiple_choice',question:'Who was Henry VII?',options:['Henry VIII\'s son','The king who defeated Richard III at Bosworth Field in 1485, founding the Tudor dynasty','The last Plantagenet king','Henry VIII\'s brother'],correct_index:1,explanation:'Henry VII was the first Tudor king. He defeated Richard III at Bosworth Field and ended the Wars of the Roses. He was Henry VIII\'s father.'},
  {id:'his-027',subject_id:'history',subject_name:'History',topic:'World Civilisations',difficulty:'foundation',type:'multiple_choice',question:'What was the "House of Wisdom" in Baghdad?',options:['The palace of the Caliph','A great library and centre of learning that translated ancient texts and produced new scholarship','A market for books','A mosque and school for religious study only'],correct_index:1,explanation:'The House of Wisdom (Bayt al-Hikma) was an extraordinary intellectual centre in Baghdad where scholars translated Greek, Persian and Indian texts and made advances in many fields.'},
  {id:'his-028',subject_id:'history',subject_name:'History',topic:'Historical skills',difficulty:'foundation',type:'multiple_choice',question:'What does the abbreviation "BCE" stand for when used in dates?',options:['Before the Common Era (before year 0)','British Cultural Evidence','Before Church Establishment','Building Construction Era'],correct_index:0,explanation:'BCE stands for "Before the Common Era" — it refers to years before year 1 AD. 500 BCE = 500 years before the birth of Christ.'},
  {id:'his-029',subject_id:'history',subject_name:'History',topic:'The Tudors',difficulty:'core',type:'multiple_choice',question:'What happened to the monasteries under Henry VIII?',options:['He built more','He closed them and took their wealth — the Dissolution of the Monasteries (1530s)','He gave them to the Catholic Church','He allowed them to become independent'],correct_index:1,explanation:'The Dissolution of the Monasteries (1536–1541) saw Henry VIII close around 900 monasteries, seizing their land and wealth. This was hugely profitable for the Crown.'},
  {id:'his-030',subject_id:'history',subject_name:'History',topic:'Historical skills',difficulty:'stretch',type:'short_answer',question:'Explain what historians mean by "interpretation". Why might two historians interpret the same event differently?',placeholder:'Define interpretation, then explain that different sources, perspectives, questions asked or political views lead to different conclusions from the same evidence...'},
  {id:'his-031',subject_id:'history',subject_name:'History',topic:'World Civilisations',difficulty:'core',type:'multiple_choice',question:'What commodity was most important to Mali\'s wealth?',options:['Silk','Spices','Gold and salt','Ivory'],correct_index:2,explanation:'Mali\'s empire sat astride the trans-Saharan trade routes for gold (from the south) and salt (from the Sahara). Control of these resources made it enormously wealthy.'},
  {id:'his-032',subject_id:'history',subject_name:'History',topic:'The Tudors',difficulty:'foundation',type:'multiple_choice',question:'Which of Henry VIII\'s children became Elizabeth I?',options:['His son by Jane Seymour','His daughter by Anne Boleyn','His daughter by Catherine of Aragon','His son by Catherine Howard'],correct_index:1,explanation:'Elizabeth I was the daughter of Henry VIII and his second wife, Anne Boleyn. She became queen in 1558 after the death of her half-sister Mary I.'},
  {id:'his-033',subject_id:'history',subject_name:'History',topic:'World Civilisations',difficulty:'stretch',type:'short_answer',question:'Compare the importance of trade to the development of two of the civilisations you have studied (e.g. Benin, Mali, Baghdad).',placeholder:'Explain how trade was central to each civilisation\'s wealth, power and cultural development, with specific examples...'},
  {id:'his-034',subject_id:'history',subject_name:'History',topic:'Historical skills',difficulty:'core',type:'multiple_choice',question:'What is "anachronism" in historical study?',options:['Placing something in the wrong time period — judging the past by today\'s standards','A very old document','A type of primary source','A method of dating artefacts'],correct_index:0,explanation:'Anachronism means applying ideas from the wrong time period. Historians avoid judging past people by modern standards — they try to understand why people thought and acted as they did in their own context.'},
  {id:'his-035',subject_id:'history',subject_name:'History',topic:'The Tudors',difficulty:'core',type:'short_answer',question:'Place the five Tudor monarchs in chronological order and give one significant fact about each.',placeholder:'Henry VII, Henry VIII, Edward VI, Mary I, Elizabeth I — with one fact per monarch...'},
  {id:'his-036',subject_id:'history',subject_name:'History',topic:'World Civilisations',difficulty:'foundation',type:'multiple_choice',question:'What was the "Oba" in the Kingdom of Benin?',options:['A type of bronze artwork','The supreme ruler (king)','A trading port','A warrior class'],correct_index:1,explanation:'The Oba was the supreme ruler of the Kingdom of Benin — a semi-divine king who held both religious and political authority.'},
  {id:'his-037',subject_id:'history',subject_name:'History',topic:'Historical skills',difficulty:'foundation',type:'short_answer',question:'Write a PEEL paragraph explaining why Henry VIII\'s break with Rome was significant. Use the structure: Point, Evidence, Explanation, Link.',placeholder:'State your point about significance, give one piece of evidence, explain it, then link back to the question...'},
  {id:'his-038',subject_id:'history',subject_name:'History',topic:'The Tudors',difficulty:'stretch',type:'short_answer',question:'Who do you think was the most significant Tudor monarch and why? Choose one and argue your case with at least two pieces of evidence.',placeholder:'Choose one Tudor, state your argument clearly, give two specific pieces of evidence, explain their significance...'},
  {id:'his-039',subject_id:'history',subject_name:'History',topic:'World Civilisations',difficulty:'core',type:'short_answer',question:'Explain what the Benin bronzes are and why their removal to British museums in 1897 is still controversial today.',placeholder:'Describe the bronzes, explain they were taken during the British Punitive Expedition, discuss the ongoing debate about repatriation...'},
  {id:'his-040',subject_id:'history',subject_name:'History',topic:'Historical skills',difficulty:'foundation',type:'multiple_choice',question:'What is a "secondary source" in history?',options:['The second document you find','A source created later, after the event, based on primary sources','A source created at the time of the event','A source that is less important'],correct_index:1,explanation:'A secondary source is created after the event by someone who wasn\'t there — usually a historian interpreting primary sources. Examples: history textbooks, documentaries, biographies.'},
  // fill to 100 with mix
  {id:'his-041',subject_id:'history',subject_name:'History',topic:'The Tudors',difficulty:'foundation',type:'multiple_choice',question:'What year did Henry VIII become king of England?',options:['1485','1503','1509','1530'],correct_index:2,explanation:'Henry VIII became king in 1509 after the death of his father Henry VII. He was 17 years old.'},
  {id:'his-042',subject_id:'history',subject_name:'History',topic:'World Civilisations',difficulty:'core',type:'multiple_choice',question:'In which century did the Mongol invasion contribute to the decline of Baghdad\'s Golden Age?',options:['10th century','11th century','13th century','15th century'],correct_index:2,explanation:'The Mongol invasion of Baghdad in 1258 destroyed the Abbasid Caliphate and the House of Wisdom, marking a major end to the Islamic Golden Age in Baghdad.'},
  {id:'his-043',subject_id:'history',subject_name:'History',topic:'Historical skills',difficulty:'core',type:'multiple_choice',question:'What does "empathy" mean in historical study?',options:['Agreeing with everything people did in the past','Trying to understand why people acted as they did given their circumstances and knowledge at the time','Feeling sorry for people who suffered','Writing emotional history essays'],correct_index:1,explanation:'Historical empathy means trying to understand the perspective, motivations and context of people in the past — not necessarily agreeing with their actions, but understanding them.'},
  {id:'his-044',subject_id:'history',subject_name:'History',topic:'The Tudors',difficulty:'foundation',type:'multiple_choice',question:'Who was Edward VI?',options:['Henry VII\'s son','Henry VIII\'s son by Jane Seymour, who became king aged 9','Henry VIII\'s son by Catherine of Aragon','Elizabeth I\'s brother who ruled before her'],correct_index:1,explanation:'Edward VI was Henry VIII\'s only legitimate son, born to Jane Seymour. He became king at age 9 in 1547 and died in 1553, aged 15, without an heir.'},
  {id:'his-045',subject_id:'history',subject_name:'History',topic:'World Civilisations',difficulty:'foundation',type:'multiple_choice',question:'In the context of history, what does "civilisation" usually mean?',options:['A city only','A complex, organised society with culture, government, writing, trade and specialist skills','Any group of people living together','Only ancient societies from Egypt or Rome'],correct_index:1,explanation:'Historians define a civilisation as a complex society with features like organised government, written language, social stratification, specialised occupations, trade and cultural achievements.'},
  {id:'his-046',subject_id:'history',subject_name:'History',topic:'Historical skills',difficulty:'stretch',type:'multiple_choice',question:'Why do historians prefer sources that were not intended for public audiences?',options:['They are easier to read','Private sources (letters, diaries) are often more candid and less influenced by desire to impress or persuade','They are always more accurate','They are older and therefore more reliable'],correct_index:1,explanation:'Private sources like personal letters and diaries tend to be more honest because the author wasn\'t trying to persuade an audience. Public speeches or official records may be deliberately crafted for a purpose.'},
  {id:'his-047',subject_id:'history',subject_name:'History',topic:'The Tudors',difficulty:'core',type:'multiple_choice',question:'What was the Privy Council?',options:['A royal bathroom','The king or queen\'s closest advisers who helped govern England','Parliament\'s lower house','The jury for treason trials'],correct_index:1,explanation:'The Privy Council was the monarch\'s inner circle of advisers — a small group of trusted officials who helped run the government.'},
  {id:'his-048',subject_id:'history',subject_name:'History',topic:'World Civilisations',difficulty:'core',type:'short_answer',question:'Explain why Al-Khwarizmi is considered significant in the history of mathematics.',placeholder:'Describe his work in algebra and the Hindu-Arabic number system, and explain the lasting impact on mathematics worldwide...'},
  {id:'his-049',subject_id:'history',subject_name:'History',topic:'Historical skills',difficulty:'foundation',type:'multiple_choice',question:'What is a "turning point" in history?',options:['A place where a battle turned around','An event that changed the course of history significantly','The middle of a historical period','A change in monarch'],correct_index:1,explanation:'A turning point is an event or moment that led to significant and lasting change in the direction of history — things were fundamentally different afterwards.'},
  {id:'his-050',subject_id:'history',subject_name:'History',topic:'The Tudors',difficulty:'stretch',type:'multiple_choice',question:'What was the "Pilgrimage of Grace" (1536)?',options:['A religious pilgrimage to Rome','A large northern rebellion against Henry VIII\'s religious changes and the Dissolution of the Monasteries','A Protestant march in support of the Reformation','Elizabeth I\'s tour of England'],correct_index:1,explanation:'The Pilgrimage of Grace was a major uprising in northern England in 1536, led by Robert Aske, against Henry VIII\'s religious reforms and the Dissolution of the Monasteries. It was eventually suppressed.'},
  {id:'his-051',subject_id:'history',subject_name:'History',topic:'World Civilisations',difficulty:'foundation',type:'multiple_choice',question:'What was the primary material used to make Benin\'s famous artworks?',options:['Stone','Wood','Bronze (brass)','Gold'],correct_index:2,explanation:'Benin\'s artworks were primarily made using bronze (an alloy of copper and tin, though often called "brass"). The intricate casting process using the lost-wax method demonstrated great technical skill.'},
  {id:'his-052',subject_id:'history',subject_name:'History',topic:'Historical skills',difficulty:'core',type:'short_answer',question:'Define the following historical concepts: continuity, change, and turning point. Give one example of each from your studies.',placeholder:'Define all three terms clearly, then give a specific historical example of each from Tudor history or World Civilisations...'},
  {id:'his-053',subject_id:'history',subject_name:'History',topic:'The Tudors',difficulty:'foundation',type:'multiple_choice',question:'Which Tudor monarch ruled the longest?',options:['Henry VII (24 years)','Henry VIII (38 years)','Elizabeth I (44 years)','Mary I (5 years)'],correct_index:2,explanation:'Elizabeth I ruled for 44 years (1558–1603), the longest reign of any Tudor monarch.'},
  {id:'his-054',subject_id:'history',subject_name:'History',topic:'World Civilisations',difficulty:'stretch',type:'short_answer',question:'Why have historians traditionally underestimated the sophistication of African civilisations? What evidence challenges this view?',placeholder:'Discuss Eurocentric bias in historical scholarship; then give specific evidence from Benin or Mali (art, trade networks, scholarship) that counters this...'},
  {id:'his-055',subject_id:'history',subject_name:'History',topic:'Historical skills',difficulty:'stretch',type:'short_answer',question:'Explain the difference between "bias" and "unreliability" in a source. Can a biased source still be historically useful?',placeholder:'Define bias (deliberate or unconscious slant) and unreliability. Argue that biased sources can reveal the author\'s viewpoint, which itself is historically valuable...'},
  {id:'his-056',subject_id:'history',subject_name:'History',topic:'The Tudors',difficulty:'core',type:'short_answer',question:'Explain how the Tudor period saw England\'s relationship with the Pope change dramatically. What were the key stages?',placeholder:'Outline: Catholic under Henry VII → Break with Rome (1530s) → Protestant Edward VI → Catholic Mary I → Protestant Elizabeth I...'},
  {id:'his-057',subject_id:'history',subject_name:'History',topic:'World Civilisations',difficulty:'foundation',type:'multiple_choice',question:'What does the word "medieval" mean?',options:['Very old and primitive','Relating to the Middle Ages (roughly 5th–15th centuries AD)','Relating to the ancient world','Meaning "advanced civilisation"'],correct_index:1,explanation:'"Medieval" means relating to the Middle Ages — roughly the period between the fall of the Western Roman Empire (476 AD) and the beginning of the Renaissance (15th century).'},
  {id:'his-058',subject_id:'history',subject_name:'History',topic:'Historical skills',difficulty:'foundation',type:'multiple_choice',question:'What does the word "interpretation" mean in history?',options:['Translating documents','A historian\'s argument about the meaning or significance of historical evidence','Ordering events chronologically','Describing what happened in detail'],correct_index:1,explanation:'An interpretation is a historian\'s argument or judgement about what the evidence shows — why something happened, how significant it was, or what it tells us about the past.'},
  {id:'his-059',subject_id:'history',subject_name:'History',topic:'The Tudors',difficulty:'core',type:'multiple_choice',question:'Why was Elizabeth I\'s decision not to marry significant?',options:['It made her unpopular','It left the succession uncertain but gave her political independence — she used marriage negotiations as a diplomatic tool','It meant England could not go to war','It made Parliament angry enough to revolt'],correct_index:1,explanation:'Elizabeth never married, which left the succession uncertain. However, she used the prospect of marriage as a diplomatic tool and avoided being subordinated to a male consort.'},
  {id:'his-060',subject_id:'history',subject_name:'History',topic:'World Civilisations',difficulty:'core',type:'multiple_choice',question:'What does "Ibn Battuta" contribute to historical knowledge of medieval civilisations?',options:['He was a general who conquered Mali','He was a Moroccan traveller who recorded observations about societies across Africa and Asia in the 14th century','He was a European merchant','He founded the Mali Empire'],correct_index:1,explanation:'Ibn Battuta (1304–1368/9) was a Moroccan scholar who travelled extensively across Africa, the Middle East and Asia, leaving detailed accounts of the societies he visited — including the Mali Empire.'},
  {id:'his-061',subject_id:'history',subject_name:'History',topic:'The Tudors',difficulty:'foundation',type:'multiple_choice',question:'What type of government did Tudor England have?',options:['A democracy','A republic','An absolute monarchy','A constitutional monarchy'],correct_index:2,explanation:'Tudor England was an absolute monarchy — the monarch had ultimate authority. Parliament existed but only met when called by the monarch and had limited power compared to today.'},
  {id:'his-062',subject_id:'history',subject_name:'History',topic:'Historical skills',difficulty:'foundation',type:'short_answer',question:'Write THREE questions you should ask when analysing a historical source to decide how useful it is.',placeholder:'E.g. Who wrote it? When was it written? Why was it written? What does it NOT tell us? Is there corroborating evidence?...'},
  {id:'his-063',subject_id:'history',subject_name:'History',topic:'World Civilisations',difficulty:'foundation',type:'multiple_choice',question:'In which modern country would the ancient Kingdom of Benin have been located?',options:['South Africa','Kenya','Nigeria','Ghana'],correct_index:2,explanation:'The Kingdom of Benin was centred in what is now Edo State in southern Nigeria. The modern city of Benin City preserves the name.'},
  {id:'his-064',subject_id:'history',subject_name:'History',topic:'The Tudors',difficulty:'stretch',type:'short_answer',question:'How far do you agree that Elizabeth I\'s reign was truly a "Golden Age" for England? Give both sides of the argument.',placeholder:'Arguments for: defeat of Armada, cultural flourishing, stability. Arguments against: poverty, religious persecution, Essex rebellion. Reach a balanced judgement...'},
  {id:'his-065',subject_id:'history',subject_name:'History',topic:'Historical skills',difficulty:'core',type:'multiple_choice',question:'When a historian cites a source, what are they doing?',options:['Copying it out in full','Referencing where their evidence comes from to show it can be verified','Making up facts','Translating the source into English'],correct_index:1,explanation:'Citing a source means providing a reference so other historians can find and verify the evidence. It is fundamental to academic honesty and historical methodology.'},
  {id:'his-066',subject_id:'history',subject_name:'History',topic:'World Civilisations',difficulty:'stretch',type:'multiple_choice',question:'What does the term "historiography" mean?',options:['Writing a history essay','The study of how history has been written and interpreted over time','A very long history book','A type of primary source'],correct_index:1,explanation:'Historiography examines how different historians have studied and interpreted the past — looking at changing methods, perspectives and arguments over time.'},
  {id:'his-067',subject_id:'history',subject_name:'History',topic:'The Tudors',difficulty:'foundation',type:'multiple_choice',question:'Where was Anne Boleyn executed?',options:['Hampton Court','The Tower of London','Westminster Abbey','Greenwich Palace'],correct_index:1,explanation:'Anne Boleyn was executed at the Tower of London on 19 May 1536, having been found guilty (likely falsely) of adultery and treason.'},
  {id:'his-068',subject_id:'history',subject_name:'History',topic:'Historical skills',difficulty:'stretch',type:'short_answer',question:'Explain what "corroboration" means in historical research and why it is important.',placeholder:'Define corroboration (confirming evidence with multiple independent sources) and explain why relying on a single source is problematic...'},
  {id:'his-069',subject_id:'history',subject_name:'History',topic:'World Civilisations',difficulty:'core',type:'multiple_choice',question:'What was significant about Mansa Musa\'s pilgrimage to Mecca in 1324?',options:['He never arrived','He showed that sub-Saharan Africa was isolated from the wider world','He demonstrated the great wealth of the Mali Empire to the wider world, causing economic disruption along his route','He converted to Christianity during the journey'],correct_index:2,explanation:'Mansa Musa travelled with an entourage of 60,000 people and distributed so much gold that he caused inflation in Egypt and other regions he passed through — demonstrating Mali\'s extraordinary wealth to the world.'},
  {id:'his-070',subject_id:'history',subject_name:'History',topic:'The Tudors',difficulty:'core',type:'multiple_choice',question:'What was Thomas Cromwell\'s role under Henry VIII?',options:['Archbishop of Canterbury','Lord Chancellor and chief minister who managed the Dissolution of the Monasteries','Henry\'s personal physician','Commander of the English navy'],correct_index:1,explanation:'Thomas Cromwell was Henry VIII\'s chief minister who managed much of the practicalities of the English Reformation, including the Dissolution of the Monasteries. He was later executed in 1540.'},
  {id:'his-071',subject_id:'history',subject_name:'History',topic:'Historical skills',difficulty:'foundation',type:'multiple_choice',question:'What is "chronology"?',options:['The study of clocks and time-keeping','Arranging events in the order they happened in time','A type of source analysis','The study of historical cause and effect'],correct_index:1,explanation:'Chronology is the arrangement of events in the order in which they occurred in time. A chronological narrative tells history in time order.'},
  {id:'his-072',subject_id:'history',subject_name:'History',topic:'World Civilisations',difficulty:'foundation',type:'short_answer',question:'Give ONE similarity and ONE difference between the Kingdom of Benin and the Mali Empire.',placeholder:'Similarity: both were powerful African kingdoms (or both had long-distance trade networks). Difference: e.g. geographical location, main source of wealth...'},
  {id:'his-073',subject_id:'history',subject_name:'History',topic:'The Tudors',difficulty:'foundation',type:'multiple_choice',question:'What was the "Reformation"?',options:['A rebuilding programme for English castles','A religious movement that challenged Catholic Church authority and led to Protestant churches','A series of political reforms to Parliament','An economic plan to reform trade'],correct_index:1,explanation:'The Reformation was a 16th-century religious movement begun by Martin Luther in Germany that challenged the authority of the Catholic Church and led to the establishment of Protestant Christianity.'},
  {id:'his-074',subject_id:'history',subject_name:'History',topic:'Historical skills',difficulty:'core',type:'short_answer',question:'Explain why it can be difficult to know exactly what happened in the past. Give two reasons why historical knowledge is uncertain.',placeholder:'Discuss: sources are incomplete/biased, not all events were recorded, sources have been destroyed, people may have lied...'},
  {id:'his-075',subject_id:'history',subject_name:'History',topic:'World Civilisations',difficulty:'core',type:'multiple_choice',question:'What was the importance of the trans-Saharan trade routes?',options:['They allowed the Roman Empire to trade with China','They connected sub-Saharan Africa with North Africa and the Mediterranean world, enabling wealth and cultural exchange','They were used exclusively for the slave trade','They were dangerous and rarely used'],correct_index:1,explanation:'The trans-Saharan trade routes linked West African kingdoms (Mali, Songhai, Benin) with North Africa and, via the Mediterranean, with Europe and the Middle East, enabling exchange of goods, ideas and religion.'},
  {id:'his-076',subject_id:'history',subject_name:'History',topic:'The Tudors',difficulty:'foundation',type:'multiple_choice',question:'Where did the Tudor dynasty get its name?',options:['From the town of Tudor in England','From Owen Tudor, Henry VII\'s grandfather, a Welsh nobleman','From a Latin word meaning "strong"','From the word for "two" because Henry had two sons'],correct_index:1,explanation:'The Tudor name comes from Owen Tudor, a Welsh nobleman who married the widow of Henry V. His grandson became Henry VII.'},
  {id:'his-077',subject_id:'history',subject_name:'History',topic:'Historical skills',difficulty:'stretch',type:'multiple_choice',question:'What does it mean if a source has "utility" for historians?',options:['It is entirely accurate','It is useful for answering a specific historical question — even biased sources can have utility','It is written in simple language','It is a primary source'],correct_index:1,explanation:'Utility means usefulness. Even a biased or unreliable source can be useful — it may tell us about the author\'s perspective, propaganda techniques or contemporary attitudes.'},
  {id:'his-078',subject_id:'history',subject_name:'History',topic:'World Civilisations',difficulty:'stretch',type:'short_answer',question:'Explain how the discovery of gold in West Africa influenced European interest in Africa during the 15th century.',placeholder:'Explain that European interest was drawn by the wealth of Mali and Songhai gold, leading to Portuguese and then other European exploration of African coasts...'},
  {id:'his-079',subject_id:'history',subject_name:'History',topic:'The Tudors',difficulty:'core',type:'short_answer',question:'Explain what "propaganda" means and give one example from Tudor history of how a monarch used it.',placeholder:'Define propaganda (information to promote a political viewpoint), then give an example such as Holbein\'s portraits of Henry VIII projecting power and authority...'},
  {id:'his-080',subject_id:'history',subject_name:'History',topic:'Historical skills',difficulty:'core',type:'multiple_choice',question:'Why is it important to study history from multiple perspectives?',options:['Because one account is always wrong','Because any single account is limited — different groups experienced events differently and all perspectives add to our understanding','Because it is required by the exam board','Because history books always contain errors'],correct_index:1,explanation:'History looks different from different perspectives — winners, losers, ordinary people, different cultures all experienced events differently. Multiple perspectives give a more complete picture.'},
  {id:'his-081',subject_id:'history',subject_name:'History',topic:'World Civilisations',difficulty:'core',type:'multiple_choice',question:'What was the Timbuktu Manuscripts project?',options:['A French attempt to destroy West African history','An effort to preserve and digitise hundreds of thousands of ancient manuscripts from Timbuktu that demonstrate the scholarly tradition of West Africa','A British museum project in the 19th century','A modern attempt to forge historical documents'],correct_index:1,explanation:'The Timbuktu Manuscripts project works to preserve and digitise thousands of medieval Islamic manuscripts from Mali, demonstrating a sophisticated literary and scholarly tradition.'},
  {id:'his-082',subject_id:'history',subject_name:'History',topic:'The Tudors',difficulty:'stretch',type:'multiple_choice',question:'What was the significance of the Act of Supremacy (1534)?',options:['It gave Parliament more power than the king','It officially made Henry VIII Supreme Head of the Church of England, completing the Break with Rome','It gave Henry VIII the power to dissolve monasteries','It established the English parliament'],correct_index:1,explanation:'The Act of Supremacy (1534) legally established Henry VIII as the Supreme Head of the Church of England, replacing the Pope. It was the constitutional foundation of the English Reformation.'},
  {id:'his-083',subject_id:'history',subject_name:'History',topic:'Historical skills',difficulty:'foundation',type:'multiple_choice',question:'What is meant by the term "contemporary source"?',options:['A modern source about an old topic','A source created at or very near the time of the events it describes','A source that many people can relate to','A source written by a famous historian'],correct_index:1,explanation:'A contemporary source was created at the time of the events — it is a primary source. For example, a diary written during the reign of Henry VIII is a contemporary source.'},
  {id:'his-084',subject_id:'history',subject_name:'History',topic:'World Civilisations',difficulty:'foundation',type:'multiple_choice',question:'Approximately when was the Islamic Golden Age of Baghdad at its peak?',options:['1st–3rd century AD','8th–13th century','15th–17th century','18th–19th century'],correct_index:1,explanation:'The Abbasid Caliphate in Baghdad was at its cultural and scientific peak from roughly the 8th to the 13th century, until the Mongol invasion of 1258.'},
  {id:'his-085',subject_id:'history',subject_name:'History',topic:'The Tudors',difficulty:'core',type:'multiple_choice',question:'What was the name of Henry VIII\'s ship that sank in the Solent in 1545?',options:['The Golden Hind','The Mary Rose','The Spanish Armada flagship','The Endeavour'],correct_index:1,explanation:'The Mary Rose was Henry VIII\'s flagship warship that sank in the Solent during a battle with the French in 1545. It was raised in 1982 and is now displayed in Portsmouth.'},
  {id:'his-086',subject_id:'history',subject_name:'History',topic:'Historical skills',difficulty:'stretch',type:'short_answer',question:'Why might it be problematic to use the term "Dark Ages" for medieval Europe? What does this term assume?',placeholder:'Explain that "Dark Ages" implies Europe had no learning or progress in this period, which is inaccurate and also Eurocentric. Other civilisations flourished simultaneously...'},
  {id:'his-087',subject_id:'history',subject_name:'History',topic:'World Civilisations',difficulty:'stretch',type:'multiple_choice',question:'What was Al-Idrisi\'s contribution to world knowledge?',options:['He founded the Mali Empire','He was an Arabic cartographer who produced detailed maps of the world in the 12th century','He led the Mongol invasion of Baghdad','He was a military general who defeated the Crusaders'],correct_index:1,explanation:'Al-Idrisi was a 12th-century Arabic geographer who created one of the most accurate maps of the world at that time, compiled for King Roger II of Sicily — demonstrating the reach of Islamic scholarship.'},
  {id:'his-088',subject_id:'history',subject_name:'History',topic:'The Tudors',difficulty:'foundation',type:'multiple_choice',question:'Who was the Archbishop of Canterbury who had Anne Boleyn\'s marriage to Henry VIII annulled?',options:['Cardinal Wolsey','Thomas Cranmer','Thomas Becket','Thomas More'],correct_index:1,explanation:'Thomas Cranmer was Henry VIII\'s Archbishop of Canterbury. He annulled Henry\'s marriages (to Anne Boleyn and others) and helped shape the Protestant Church of England.'},
  {id:'his-089',subject_id:'history',subject_name:'History',topic:'Historical skills',difficulty:'core',type:'short_answer',question:'Explain the difference between a "short-term" cause and a "long-term" cause. Give one of each for the Break with Rome.',placeholder:'Define both terms, then give a specific short-term cause (Henry\'s desire for annulment) and long-term cause (existing tensions with the papacy, desire for church wealth)...'},
  {id:'his-090',subject_id:'history',subject_name:'History',topic:'World Civilisations',difficulty:'core',type:'short_answer',question:'Describe what a traveller visiting Benin City in the 15th or 16th century might have seen that impressed them. Use specific evidence.',placeholder:'Describe wide streets, the Oba\'s palace, the army, market activity, bronze artworks — reference accounts from European traders or modern archaeological evidence...'},
  {id:'his-091',subject_id:'history',subject_name:'History',topic:'The Tudors',difficulty:'core',type:'multiple_choice',question:'What was the role of Thomas More in relation to Henry VIII?',options:['He was Henry\'s court jester','He was Henry\'s Lord Chancellor who refused to accept the Break with Rome and was executed for treason','He was Henry\'s military commander','He was the first Protestant Archbishop of Canterbury'],correct_index:1,explanation:'Thomas More was Henry\'s Lord Chancellor and close friend. He refused to swear the Oath of Supremacy (accepting Henry as Head of the Church) on religious grounds and was executed in 1535.'},
  {id:'his-092',subject_id:'history',subject_name:'History',topic:'Historical skills',difficulty:'foundation',type:'multiple_choice',question:'What does the term "change over time" mean in history?',options:['Looking at how quickly people could travel','Examining how a situation or condition developed differently across a historical period','Comparing two different countries','Looking at a single event in detail'],correct_index:1,explanation:'"Change over time" means looking at how something (e.g. religious practice, living conditions, women\'s rights) developed or altered across a historical period.'},
  {id:'his-093',subject_id:'history',subject_name:'History',topic:'World Civilisations',difficulty:'foundation',type:'multiple_choice',question:'What does the word "Oba" mean in the Benin Kingdom?',options:['Gold','God','King (supreme ruler)','Bronze'],correct_index:2,explanation:'Oba is the title for the supreme ruler (king) of the Kingdom of Benin. The Oba had both political and religious authority and was considered semi-divine.'},
  {id:'his-094',subject_id:'history',subject_name:'History',topic:'The Tudors',difficulty:'stretch',type:'multiple_choice',question:'What was the significance of the English Reformation for ordinary people in England?',options:['It had no effect on ordinary life','Church services changed, monasteries that provided welfare closed, religious art was destroyed, and the English Bible was introduced','It made England more Catholic','It improved living standards for all'],correct_index:1,explanation:'Ordinary people experienced enormous change: Mass was now in English, not Latin; religious images were destroyed; monasteries that had provided healthcare and education were closed; the Bible was made available in English.'},
  {id:'his-095',subject_id:'history',subject_name:'History',topic:'Historical skills',difficulty:'core',type:'multiple_choice',question:'If a source is "one-sided", does that make it worthless to historians?',options:['Yes, biased sources should be ignored','No — a biased source can reveal the author\'s perspective, which is itself historically valuable','Yes, historians should only use balanced sources','No, but only if it is a primary source'],correct_index:1,explanation:'Biased sources can be very valuable — they reveal what the author thought, believed or wanted others to believe, which is itself historically important. A Tudor propaganda portrait reveals what image the Crown wanted to project.'},
  {id:'his-096',subject_id:'history',subject_name:'History',topic:'World Civilisations',difficulty:'stretch',type:'short_answer',question:'How does the history of the Benin bronzes raise questions about museum ownership and cultural heritage? What are the arguments on both sides?',placeholder:'Discuss: British museums argue they preserve the works; Nigeria argues the bronzes were taken during colonial aggression and should be returned. Give arguments for each position...'},
  {id:'his-097',subject_id:'history',subject_name:'History',topic:'The Tudors',difficulty:'foundation',type:'multiple_choice',question:'What was the Church of England\'s position on religion when Elizabeth I came to power?',options:['Strongly Catholic','Strongly Calvinist Protestant','A moderate Protestantism — the Elizabethan Religious Settlement of 1559','Entirely secular'],correct_index:2,explanation:'The Elizabethan Religious Settlement (1559) established a moderate Protestant Church of England — Catholic in ceremony but Protestant in theology — attempting to unite England after religious upheaval.'},
  {id:'his-098',subject_id:'history',subject_name:'History',topic:'Historical skills',difficulty:'stretch',type:'short_answer',question:'Explain what historians mean by "change and continuity". Give one example of change and one example of continuity in Tudor England.',placeholder:'Define both terms, then give a specific Tudor example of something that changed (religion) and something that continued (monarch\'s power, Parliament\'s existence)...'},
  {id:'his-099',subject_id:'history',subject_name:'History',topic:'World Civilisations',difficulty:'core',type:'multiple_choice',question:'What does the term "trans-Saharan trade" mean?',options:['Trade within the Sahara Desert','Trade across the Sahara Desert connecting West Africa with North Africa and the Mediterranean','Trade by sea around Africa','Trade between East and West Africa'],correct_index:1,explanation:'Trans-Saharan trade routes crossed the Sahara Desert, connecting West African kingdoms (which produced gold, salt, slaves, ivory) with North Africa, Egypt and the Mediterranean world.'},
  {id:'his-100',subject_id:'history',subject_name:'History',topic:'Historical skills',difficulty:'core',type:'short_answer',question:'Write a definition for five of these historical terms: primary source, secondary source, causation, significance, anachronism, chronology, interpretation.',placeholder:'Write a clear, concise definition for five of the listed terms in your own words...'},
]
